    24	@implementation WBPopupManager
    25	
    26	
    27	+ (instancetype)sharedManager {
    28	    static id instance;
    29	    static dispatch_once_t onceToken;
    30	    dispatch_once(&onceToken, ^{
    31	        instance = [[WBPopupManager alloc] init];
    32	    });
    33	    return instance;
    34	}
    35	
    36	- (instancetype)init {
    37	    self = [super init];
    38	    if (self) {
    39	        self.popups = [NSMutableArray array];
    40	    }
    41	    return self;
    42	}
    43	
    44	
    45	- (void)initPopups:(NSArray<WBNoticeModel*> *)popups {
    46	    [self.popups addObjectsFromArray:popups];
    47	}
    48	
    49	- (void)showPopup {
    50	    if (!self.popups.count) return;
    51	    void (^showPopupBlock)(void) = ^{
    52	        UIViewController *rootVC = [WBAppManager getUIApplicationRootViewController];
    53	        UIViewController *hostVC = rootVC.presentedViewController ?: rootVC;
    54	        if ([hostVC isKindOfClass:[UIAlertController class]]) return;
    55	        WBNoticeModel *notice = self.popups.firstObject;
    56	        UIViewController *popupVC = [self getPopupVCWithNotice:notice];
    57	        [hostVC presentViewController:popupVC animated:false completion:nil];
    58	        if (notice.popupId != -1) {
    59	            [WBNetworkManager.defaultManager sendPopupId:notice.popupId];   // 上报默认弹窗已展示
    60	        } else if(notice.scheduleId != -1) {
    61	            [WBNetworkManager.defaultManager sendScheduleId:notice.scheduleId]; // 上报优惠券默认弹窗已展示
    62	        }
    63	        self.presentedPopup = popupVC;
    64	        self.notice = notice;
    65	        [self.popups popFirstObject];
    66	    };
    67	    if (self.presentedPopup) {
    68	        [self.presentedPopup dismissViewControllerAnimated:NO completion:showPopupBlock];
    69	    } else {
    70	        showPopupBlock();
    71	    }
    72	}
    73	
    74	- (UIViewController *)getPopupVCWithNotice:(WBNoticeModel *)notice {
    75	    UIViewController *popupVC = nil;
    76	    if (notice.style == WBNoticeStylePopUp) {
    77	        popupVC = [WBPopupViewController controllerWithNotice:notice];
    78	    } else if (notice.style == WBNoticeStyleSystemAlert) {
    79	        popupVC = [WBPopUpAlertController controllerWithNotice:notice];
    80	    }
    81	    return popupVC;
    82	}
    83	
    84	- (void)dismissPopup {
    85	    [self.presentedPopup dismissViewControllerAnimated:NO completion:^{
    86	        [[NSNotificationCenter defaultCenter] postNotificationName:WBPopupDismissNotification object:nil];
    87	        if (self.popups.count > 0) {
    88	            [self showPopup];
    89	        } else {
    90	            self.presentedPopup = nil;
    91	            self.notice = nil;
    92	        }
    93	    }];
    94	}
    95	
    96	- (void)operationClicked:(WBRichMessageLinkModel *)operation style:(WBNoticeStyle)style {
    97	    [WBNetworkManager.defaultManager sendNoticeEvent:style richMessageLinkId:operation.richMessageLinkId popupName:self.notice.name eventName:operation.label];
    98	    operation.action = [self getActionBlock:operation];
    99	    if (operation.action) {
   100	        operation.action();
   101	    }
   102	    if (operation.postAction) {
   103	        operation.postAction();
   104	    }
   105	    if (operation.isDismissOnTap) {
   106	        [self dismissPopup];
   107	    }
   108	}
   109	
   110	- (WBActionBlock)getActionBlock:(WBRichMessageLinkModel *)link{
   111	    @weakify(self)
   112	    WBActionBlock block = NULL;
   113	    switch(link.type) {
   114	        case WBRichMessageLinkTypeArticle:
   115	        case WBRichMessageLinkTypeWebview:
   116	            if (1) {
   117	                block = ^{
   118	                    @strongify(self)
   119	                    WBWebViewController *webVC = [[WBWebViewController alloc] initWithURL:[NSURL URLWithString:link.link]];
   120	                    if ([self.presentedPopup isKindOfClass:[UINavigationController class]]) {
   121	                        [(UINavigationController *)self.presentedPopup pushViewController:webVC animated:YES];
   122	                    } else {
   123	                        [self.presentedPopup dismissViewControllerAnimated:false completion:^{
   124	                            UIViewController *rootVC = [WBAppManager getUIApplicationRootViewController];
   125	                            [rootVC presentViewController:webVC animated:true completion:nil];
   126	                            if (link.isDismissOnTap) return;
   127	                            webVC.dismissBlock = ^{
   128	                                [rootVC presentViewController:self.presentedPopup animated:true completion:nil];
   129	                            };
   130	                        }];
   131	                    }
   132	                };
   133	            }
   134	            break;
   135	        case WBRichMessageLinkTypeAppstoreRate:
   136	            if (1) {
   137	                block = ^{
   138	                    [WBAppManager.sharedManager writeReviewInAppStore:@"popup"];
   139	                };
   140	            }
   141	            break;
   142	        case WBRichMessageLinkTypeDismiss:
   143	            if (1) {
   144	                block = ^{
   145	                    @strongify(self)
   146	                    [self dismissPopup];
   147	                };
   148	            }
   149	            break;
   150	        case WBRichMessageLinkTypeExit:
   151	            if (1) {
   152	                block = ^{
   153	                    exit(0);
   154	                };
   155	            }
   156	            break;
   157	        case WBRichMessageLinkTypeDefault:
   158	            if (self.stashedDefaultHandler) {
   159	                block = self.stashedDefaultHandler;
   160	                self.stashedDefaultHandler = nil;
   161	            }
   162	            break;
   163	        default:
   164	            if (link.generalAction) {
   165	                block = link.generalAction;
   166	            } else {
   167	                NSLog(@"no action defined for operation:%@", link.label);
   168	            }
   169	            break;
   170	    }
   171	    return block;
   172	}
   173	
   174	@end

