    23	+ (instancetype)controllerWithNotice:(WBNoticeModel *)notice {
    24	    WBPopUpAlertController *popupVC = [self alertControllerWithTitle:notice.title message:notice.content preferredStyle:UIAlertControllerStyleAlert];
    25	    for (WBRichMessageLinkModel *op in notice.operations) {
    26	        UIAlertActionStyle style = 0;
    27	        if (op.style == WBRichMessageLinkStylePrimary) {
    28	            style = UIAlertActionStyleDefault;
    29	        } else if (op.style == WBRichMessageLinkStyleNormal) {
    30	            style = UIAlertActionStyleCancel;
    31	        } else if (op.style == WBRichMessageLinkStyleGrey) {
    32	            style = UIAlertActionStyleDestructive;
    33	        }
    34	        UIAlertAction *action = [UIAlertAction actionWithTitle:op.label style:style handler:nil];
    35	        [popupVC addAction:action];
    36	    }
    37	    if (popupVC) {
    38	        popupVC.notice = notice;
    39	    }
    40	    return popupVC;
    41	}
