    43	- (void)viewWillAppear:(BOOL)animated {
    44	    [super viewWillAppear:animated];
    45	    if (self.onceToken) return;
    46	    self.view.subviews[0].userInteractionEnabled = false;
    47	    int index = 0;
    48	    for (WBRichMessageLinkModel *op in self.notice.operations) {
    49	        [self setUpNativeAlertActionViewWithOperation:op index:index];
    50	        index++;
    51	    }
    52	    self.onceToken = true;
    53	}
    54	
    55	- (void)setUpNativeAlertActionViewWithOperation:(WBRichMessageLinkModel *)operation index:(int)index {
    56	    UILabel *actionLabel = [self getActionLabelWithOperaton:operation];
    57	    UIView *actionView = [self getActionViewWithActionLabel:actionLabel];
    58	    UIButton *transparentButton = [UIButton buttonWithType:UIButtonTypeCustom];
    59	//        transparentButton.backgroundColor = [UIColor grayColor];
    60	//        [transparentButton setTitleColor:[UIColor whiteColor] forState:UIControlStateNormal];
    61	//        [transparentButton setTitle:op.label forState:UIControlStateNormal];
    62	    transparentButton.tag = index;
    63	    [transparentButton addTarget:self action:@selector(buttonClicked:) forControlEvents:UIControlEventTouchUpInside];
    64	    [self.view addSubview:transparentButton];
    65	    [transparentButton mas_makeConstraints:^(MASConstraintMaker *make) {
    66	        make.edges.equalTo(actionView);
    67	    }];
    68	    if (operation.timeout) {
    69	        transparentButton.userInteractionEnabled = false;
    70	        NSTimer *timer = [NSTimer scheduledTimerWithTimeInterval:1.0 block:^(NSTimer * _Nonnull timer) {
    71	            if (operation.timeout) {
    72	                NSString *title = [operation.label stringByAppendingFormat:@"  (%d)", operation.timeout];
    73	                actionLabel.text = title;
    74	                operation.timeout--;
    75	            } else {
    76	                actionLabel.text = operation.label;
    77	                [timer invalidate];
    78	                transparentButton.userInteractionEnabled = true;
    79	            }
    80	        } repeats:true];
    81	        [timer fire];
    82	    }
    83	}
