    23	    if (self.isPresenting) { // 如果正在呈现弹窗
    24	        toViewController.view.alpha = 0.0;
    25	        [containerView insertSubview:toViewController.view atIndex:0];
    26	        
    27	        [UIView animateWithDuration:[self transitionDuration:transitionContext] animations:^{
    28	            toViewController.view.alpha = 1.0;
    29	        } completion:^(BOOL finished) {
    30	            [transitionContext completeTransition:YES];
    31	        }];
    32	    } else { // 如果正在关闭弹窗
    33	        [UIView animateWithDuration:[self transitionDuration:transitionContext] animations:^{
    34	            fromViewController.view.alpha = 0.0;
    35	        } completion:^(BOOL finished) {
    36	            [fromViewController.view removeFromSuperview];
    37	            [transitionContext completeTransition:YES];
    38	        }];
    39	    }
    40	}
    41	
    42	
    43	@end
