    37	    if (index == -1) {
    38	        [WBNetworkManager.defaultManager sendNoticeEvent:self.popupStyle richMessageLinkId:self.mainImageRichMessageLinkId popupName:self.richMessageNoticeName eventName:self.mainImageRichMessageLinkLabel];
    39	    } else {
    40	        if (index < self.buttonData.count) {
    41	            NSDictionary *data = self.buttonData[index];
    42	            [WBNetworkManager.defaultManager sendNoticeEvent:self.popupStyle richMessageLinkId:data[@"id"] popupName:self.richMessageNoticeName eventName:data[@"label"]];
    43	        }
    44	    }
    45	}
