    47	
    48	- (void)showCustomPopupWithUserInfo:(NSDictionary *)popupInfo {
    49	    NSString *imageUrlString = popupInfo[@"rich_message"][@"image"];
    50	    NSURL *imageUrl = [NSURL URLWithString:imageUrlString];
    51	    NSString *linkURL = popupInfo[@"rich_message"][@"links"][0][@"link"];    // 活动弹窗跳转链接（links数组的第一个link）
    52	    NSString *richMessageLinkId = [popupInfo[@"rich_message"][@"links"][0][@"id"] stringValue];
    53	    NSString *linkType = popupInfo[@"rich_message"][@"links"][0][@"type"];
    54	    NSString *dismiss = popupInfo[@"rich_message"][@"links"][0][@"dismiss"];
    55	    
    56	    // 通过数组切片剔除第一个元素
    57	    NSArray *links = popupInfo[@"rich_message"][@"links"];
    58	    self.buttonData = [links subarrayWithRange:NSMakeRange(1, links.count - 1)]; // 从第二个元素开始
    59	    
    60	    self.popupStyle = (WBNoticeStyle)[popupInfo[@"rich_message"][@"style"] integerValue];
    61	    self.mainImageRichMessageLinkId = popupInfo[@"rich_message"][@"links"][0][@"id"];
    62	    self.richMessageNoticeName = popupInfo[@"rich_message"][@"name"];
    63	    self.mainImageRichMessageLinkLabel = popupInfo[@"rich_message"][@"links"][0][@"label"];
    64	    
    65	    // 异步加载图片，避免阻塞主线程
    66	    dispatch_async(dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_DEFAULT, 0), ^{
    67	        NSData *imageData = [NSData dataWithContentsOfURL:imageUrl];
    68	        UIImage *image = [UIImage imageWithData:imageData];
    69	        
    70	        // 回到主线程更新UI
    71	        dispatch_async(dispatch_get_main_queue(), ^{
    72	            WBVAppModel *runningVApp = [WBVAppManager sharedManager].runningVApp;
    73	            if(!runningVApp) {
    74	                WBCustomPopupViewController *customPopupVC = [[WBCustomPopupViewController alloc] initWithImageName:image linkURL:linkURL richMessageLinkId:richMessageLinkId linkType:linkType dismiss:dismiss buttonData:self.buttonData];
    75	                customPopupVC.delegate = self;    // 设置 delegate
    76	                customPopupVC.modalPresentationStyle = UIModalPresentationOverFullScreen;
    77	                customPopupVC.transitioningDelegate = customPopupVC;
    78	                
    79	                UIViewController *currentViewController = [WBAppManager getUIApplicationRootViewController];
    80	                // 循环查找，尝试找到当前展示的视图控制器
    81	                while (currentViewController.presentedViewController != nil) {
    82	                    currentViewController = currentViewController.presentedViewController;
    83	                }
    84	                // 检查视图是否已经加入窗口层级
    85	                if (!currentViewController.view.window) {
    86	                    // 如果没有找到当前模态视图控制器，则退回到使用 WBAppManager 的根视图控制器
    87	                    currentViewController = [WBAppManager getUIApplicationRootViewController];
    88	                    if (!currentViewController.view.window) {
    89	                        // 若根视图控制器不在窗口视图中，打印错误信息并终止方法的执行
    90	                        NSLog(@"Error: Neither the current nor the root view controller's views are in the window hierarchy. Cannot present WBCustomPopupViewController.");
    91	                        return;
    92	                    }
    93	                }
    94	                [currentViewController presentViewController:customPopupVC animated:YES completion:nil];    // 展示活动弹窗
    95	                if([popupInfo[@"rich_message"] objectForKey:@"popupId"]) {
    96	                    NSInteger popupId = [popupInfo[@"rich_message"][@"popupId"] intValue];
    97	                    [WBNetworkManager.defaultManager sendPopupId:popupId];  // 上报图片弹窗已展示
    98	                } else if([popupInfo[@"rich_message"] objectForKey:@"scheduleId"]) {
    99	                    NSInteger scheduleId = [popupInfo[@"rich_message"][@"scheduleId"] intValue];
   100	                    [WBNetworkManager.defaultManager sendScheduleId:scheduleId];  // 上报优惠券图片弹窗已展示
   101	                }
   102	            }
   103	        });
   104	    });
   105	}
