   108	- (void)customPopupDidDismiss {
   109	    [[NSNotificationCenter defaultCenter] postNotificationName:CustomPopupDismissedNotification object:nil];     // 发送通知，告诉消息中心，活动弹窗已关闭
   110	    if (self.stashedDefaultHandler) {
   111	        // self.stashedDefaultHandler();    // 不执行之前默认的事件（老一套的vapp启动）
   112	        self.stashedDefaultHandler = nil;
   113	    }
   114	    self.currentViewController = nil;
   115	}
