    34	@implementation WBDynamicPopupViewController
    35	
    36	- (instancetype)initWithAmain:(NSDictionary *)Amain Bmain:(NSDictionary *)Bmain Asub:(NSDictionary *)Asub Bsub:(NSDictionary *)Bsub frontAnimation:(NSDictionary *)frontAnimation rearAnimation:(NSDictionary *)rearAnimation linkUrl:(NSString *)linkUrl richMessageLinkId:(NSString *)richMessageLinkId AnimationAtEnd:(NSDictionary *)animationAtEnd linkType:(NSString *)linkType dismiss:(NSString *)dismiss{
