   126	#pragma mark - function
   127	
   128	- (void)whichEndType:(NSString *)animationEndType {
   129	    NSString *type = self.animationAtEnd[animationEndType];
   130	    if ([type isEqual:@"disappear"]) {
   131	        self.handleAnimationEndType = handleAnimationAtEnd_Disappear;
   132	    } else if ([type isEqual:@"loop"]) {
   133	        self.handleAnimationEndType = handleAnimationAtEnd_Loop;
   134	    } else if ([type isEqual:@"pause"]) {
   135	        self.handleAnimationEndType = handleAnimationAtEnd_Pause;
   136	    } else {
   137	        self.handleAnimationEndType = handleAnimationAtEnd_Default;     // 播放完全部暂停
   138	    }
   139	}
   140	
   141	- (void)handleEndWithAnimationVC:(WBDynamicAnimationViewController *)animationVC withType:(NSString *)type{
   142	    switch (self.handleAnimationEndType) {
   143	        case handleAnimationAtEnd_Disappear:
   144	            if ([type isEqual:@"main"]) {
   145	                self.animationVC.view.hidden = YES;
   146	            } else {
   147	                [animationVC disappear];
   148	            }
   149	            break;
   150	        case handleAnimationAtEnd_Loop:
   151	            [animationVC loop];
   152	            break;
   153	        case handleAnimationAtEnd_Pause:
   154	            [animationVC pause];
   155	            break;
   156	        default:
   157	            break;
   158	    }
   159	}
