   161	
   162	- (void)appearA {
   163	    if (self.Amain) {   // 如果A面动画的资源存在
   164	        [self.animationVC updateWithJson:self.Amain];
   165	        
   166	        [self.animationVC playWithCompletion:^(BOOL animationFinished) {
   167	            if (animationFinished) {
   168	                [self whichEndType:@"A_main"];
   169	                [self handleEndWithAnimationVC:self.animationVC withType:@"main"];
   170	                
   171	                if (self.Asub) {
   172	                    self.AsubAnimationVC.view.hidden = NO;
   173	                    [self whichEndType:@"A_sub"];
   174	                    [self handleEndWithAnimationVC:self.AsubAnimationVC withType:@"sub"];
   175	                }
   176	                self.closeButton.hidden = NO;
   177	                
   178	                UITapGestureRecognizer *tapGesture = [[UITapGestureRecognizer alloc] initWithTarget:self action:@selector(TappedA:)];
   179	                tapGesture.numberOfTapsRequired = 1;
   180	                [self.animationVC.view addGestureRecognizer:tapGesture];
   181	                if (self.Asub) {
   182	                    [self.AsubAnimationVC.view addGestureRecognizer:tapGesture];
   183	                }
   184	            }
   185	        }];
   186	    } else {
   187	        [self dismissPopupWithCompletion:nil];
   188	    }
   189	}
   190	
   191	- (void)TappedA:(UITapGestureRecognizer *)gestureRecognizer {
   192	    [[WBDynamicPopupResUnzip sharedManager] sendClickEvent];    // 点击事件上报
   193	    if (self.isHandlingTappedA) {
   194	        // 同一时间段，只处理最早的一个点击事件
   195	        return;
   196	    }
   197	    self.isHandlingTappedA = YES;
   198	    
   199	    if([self.linkType integerValue] == linkType_Dismiss || [self.linkType integerValue] == linkType_Default) {
   200	        [self dismissPopupWithCompletion:^{
   201	            self.isHandlingTappedA = NO;
   202	        }];
   203	    } else if ([self.linkType integerValue] == linkType_UrlScheme) {
   204	        if ([self.linkUrl hasPrefix:@"webox:///page"]) {
   205	            __block NSURL *pageUrl = [NSURL URLWithString:self.linkUrl];
   206	            NSString *triggerId = self.richMessageLinkId ?: nil;
   207	            if ([pageUrl.absoluteString isEqualToString:@"webox:///page/vip"] && triggerId) {
   208	                NSURLComponents *components = [NSURLComponents componentsWithString:pageUrl.absoluteString];
   209	                NSMutableArray<NSURLQueryItem *> *queryItems = [components.queryItems mutableCopy] ?: [NSMutableArray new];
   210	                NSURLQueryItem *triggerItem = [NSURLQueryItem queryItemWithName:@"triggerId" value:triggerId];
   211	                [queryItems addObject:triggerItem];
   212	                components.queryItems = queryItems;
   213	                pageUrl = components.URL;
   214	            }
   215	            dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.5 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
   216	                [self dismissPopupWithCompletion:^{
   217	                    [[WBRouteManager sharedManager] performRoute:pageUrl sourceInterface:@"action/popup"];
   218	                    self.isHandlingTappedA = NO;
   219	                }];
   220	            });
   221	        } else if ([self.linkUrl hasPrefix:@"webox:///action"]) {
   222	            
   223	            NSURL *url = [NSURL URLWithString:self.linkUrl];
   224	            dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.01 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
   225	                if ([self.linkUrl hasPrefix:@"webox:///action/promoReceive"]) {
   226	                    [[NSNotificationCenter defaultCenter] postNotificationName:WBDynamicPromoReceiveNotification object:nil];
   227	                }
   228	                [[WBRouteManager sharedManager] performRoute:url sourceInterface:@"action/popup"];  // 活动弹窗链接跳转路由
   229	                [self dismissPopupWithCompletion:nil];
   230	            });
   231	            
   232	            self.AsubAnimationVC.view.hidden = YES;
